-- Generated by build_clues.py — rebuild puzzles.clues (6 state + 6 district hints).
-- State deck precomputed per state; district deck computed from the live census jsonb.
UPDATE puzzles p SET clues = jsonb_build_object('state', st.deck, 'district',
jsonb_build_array(
  jsonb_build_object('icon','people','label','Median age','value',
    (p.census->>'medianAge') || ' years'),
  jsonb_build_object('icon','dollar','label','Median household income','value',
    '$' || to_char((p.census->>'income')::numeric,'FM999,999') || '/yr'),
  jsonb_build_object('icon','people','label','Largest racial/ethnic group','value',
    CASE
      WHEN (p.census->>'whiteNH')::numeric>=(p.census->>'black')::numeric AND (p.census->>'whiteNH')::numeric>=(p.census->>'asian')::numeric AND (p.census->>'whiteNH')::numeric>=(p.census->>'hispanic')::numeric THEN round(100*(p.census->>'whiteNH')::numeric/(p.census->>'pop')::numeric)::int||'% White'||CASE WHEN (p.census->>'whiteNH')::numeric/(p.census->>'pop')::numeric>0.5 THEN ' majority' ELSE ' plurality' END
      WHEN (p.census->>'black')::numeric>=(p.census->>'asian')::numeric AND (p.census->>'black')::numeric>=(p.census->>'hispanic')::numeric THEN round(100*(p.census->>'black')::numeric/(p.census->>'pop')::numeric)::int||'% Black'||CASE WHEN (p.census->>'black')::numeric/(p.census->>'pop')::numeric>0.5 THEN ' majority' ELSE ' plurality' END
      WHEN (p.census->>'asian')::numeric>=(p.census->>'hispanic')::numeric THEN round(100*(p.census->>'asian')::numeric/(p.census->>'pop')::numeric)::int||'% Asian'||CASE WHEN (p.census->>'asian')::numeric/(p.census->>'pop')::numeric>0.5 THEN ' majority' ELSE ' plurality' END
      ELSE round(100*(p.census->>'hispanic')::numeric/(p.census->>'pop')::numeric)::int||'% Hispanic'||CASE WHEN (p.census->>'hispanic')::numeric/(p.census->>'pop')::numeric>0.5 THEN ' majority' ELSE ' plurality' END
    END),
  jsonb_build_object('icon','flag','label','2024 Presidential vote','value',
    (CASE WHEN (p.census->>'Margin2024Pres')::numeric>0.30 THEN 'Strongly Democratic' WHEN (p.census->>'Margin2024Pres')::numeric>0.10 THEN 'Likely Democratic'
          WHEN (p.census->>'Margin2024Pres')::numeric>0.03 THEN 'Lean Democratic' WHEN (p.census->>'Margin2024Pres')::numeric>=-0.03 THEN 'Competitive'
          WHEN (p.census->>'Margin2024Pres')::numeric>-0.10 THEN 'Lean Republican' WHEN (p.census->>'Margin2024Pres')::numeric>-0.30 THEN 'Likely Republican'
          ELSE 'Strongly Republican' END)
    || ' — ' || (CASE WHEN (p.census->>'Margin2024Pres')::numeric>=0 THEN 'D+' ELSE 'R+' END)
    || to_char(round(100*abs((p.census->>'Margin2024Pres')::numeric),1),'FM990.0') || '% ('
    || round(100*(p.census->>'DemPct2024Pres')::numeric)::int || 'D / ' || round(100*(p.census->>'RepPct2024Pres')::numeric)::int || 'R)'),
  jsonb_build_object('icon','ruler','label','Population density','value',
    (CASE WHEN ((p.census->>'pop')::numeric/NULLIF((p.census->>'area_sqmi')::numeric,0))>10000 THEN 'Dense urban' WHEN ((p.census->>'pop')::numeric/NULLIF((p.census->>'area_sqmi')::numeric,0))>2000 THEN 'Urban / suburban'
          WHEN ((p.census->>'pop')::numeric/NULLIF((p.census->>'area_sqmi')::numeric,0))>500 THEN 'Suburban' WHEN ((p.census->>'pop')::numeric/NULLIF((p.census->>'area_sqmi')::numeric,0))>100 THEN 'Exurban / small-town'
          ELSE 'Rural' END)
    || ' — ' || to_char(round(((p.census->>'pop')::numeric/NULLIF((p.census->>'area_sqmi')::numeric,0))),'FM999,999') || ' people / sq mi'),
  jsonb_build_object('icon','building','label','Current representative','value',
    (p.census->'rep'->>'name') || COALESCE(' (' || (p.census->'rep'->>'partyCode') || ')',''))
)
)
